+							std::cref(dataset),
+							std::cref(centroids),
+							std::cref(weight),
+							std::ref(centroids_buf[c]),
+							std::ref(cluster_size_buf[c]),
+							i, min(n, i + block_size)), 0));
+		}
+
+		real_t distsqr_sum = 0;
